return (() => {
  const badgeId = 'mole-takeover-badge';
  const text = '{{takeover_badge_text}}' || 'Mole 接管中';
  let badge = document.getElementById(badgeId);
  if (!badge) {
    badge = document.createElement('div');
    badge.id = badgeId;
    badge.style.position = 'fixed';
    badge.style.right = '20px';
    badge.style.bottom = '20px';
    badge.style.zIndex = '2147483647';
    badge.style.padding = '10px 12px';
    badge.style.borderRadius = '999px';
    badge.style.background = 'rgba(22, 163, 74, 0.9)';
    badge.style.color = '#fff';
    badge.style.fontSize = '12px';
    badge.style.fontWeight = '600';
    badge.style.boxShadow = '0 10px 30px rgba(0,0,0,0.22)';
    badge.style.pointerEvents = 'none';
    document.body.appendChild(badge);
  }
  badge.textContent = text;
  badge.setAttribute('data-updated-at', String(Date.now()));
  return { badgeId, text, pageUrl: location.href, pageTitle: document.title };
})();

return (() => {
  const toText = (value) => (value || '').replace(/\s+/g, ' ').trim();
  const listItems = Array.from(document.querySelectorAll('ul[role="group"] li[role="listitem"]'));
  const targetName = toText('{{target_name}}');
  const targetIndexRaw = Number('{{conversation_index}}');
  const hasTargetIndex = Number.isFinite(targetIndexRaw) && targetIndexRaw >= 0;
  const conversations = listItems.map((li, index) => {
    const card = li.querySelector('.friend-content') || li;
    const name = toText((card.querySelector('.name-text') || card.querySelector('.name-box'))?.textContent || '');
    const company = toText(card.querySelector('.name-box span:nth-child(2)')?.textContent || '');
    const role = toText(card.querySelector('.name-box span:nth-child(4)')?.textContent || '');
    const lastMsg = toText(card.querySelector('.last-msg-text')?.textContent || '');
    const isSelected = card.classList.contains('selected') || li.querySelector('.friend-content.selected') != null;
    return { index, name, company, role, lastMsg, selected: isSelected };
  });
  const activeIndex = conversations.findIndex((item) => item.selected);
  let targetIndex = activeIndex >= 0 ? activeIndex : (conversations.length > 0 ? 0 : -1);
  if (targetName) {
    const byName = conversations.findIndex((item) => toText(item.name).includes(targetName));
    if (byName >= 0) targetIndex = byName;
  } else if (hasTargetIndex && targetIndexRaw < conversations.length) {
    targetIndex = Math.floor(targetIndexRaw);
  }
  const targetSelector = targetIndex >= 0 ? ('ul[role="group"] li[role="listitem"]:nth-child(' + String(targetIndex + 1) + ') .friend-content') : '';
  return { pageUrl: location.href, pageTitle: document.title, listReady: conversations.length > 0, conversationCount: conversations.length, activeIndex, targetIndex, targetSelector, shouldSwitchConversation: targetIndex >= 0 && targetIndex !== activeIndex, conversations };
})();

return (() => {
  const toText = (value) => (value || '').replace(/\s+/g, ' ').trim();
  const panel = document.querySelector('[class*="chat-content"],[class*="message-list"],[class*="dialogue"],[class*="conversation-content"]');
  const root = panel || document.body;
  const messageNodes = Array.from(root.querySelectorAll('[class*="message"] [class*="text"],[class*="message"],[class*="msg"]'));
  const recentMessages = messageNodes.map((node) => toText(node.textContent || '')).filter(Boolean).slice(-20);
  const inputNode = document.querySelector('textarea,[contenteditable="true"],div[role="textbox"],input[type="text"]');
  const activeNameNode = document.querySelector('ul[role="group"] li[role="listitem"] .friend-content.selected .name-text');
  const autoSendRaw = '{{auto_send}}';
  const replyTextRaw = '{{reply_text}}';
  const shouldAutoSend = /^(true|1|yes)$/i.test(String(autoSendRaw)) && toText(replyTextRaw).length > 0;
  return { pageUrl: location.href, pageTitle: document.title, activeConversationName: toText(activeNameNode?.textContent || ''), recentMessages, replyBoxSelector: inputNode ? 'textarea,[contenteditable="true"],div[role="textbox"],input[type="text"]' : '', canReply: Boolean(inputNode), shouldAutoSend, replyText: toText(replyTextRaw) };
})();
